import{_ as l,c as i}from"./app.5ef9faad.js";const a={},e=i('<h1 id="\u5B9E\u65BD\u654F\u6377-\u521B\u5EFA\u654F\u6377\u73AF\u5883" tabindex="-1"><a class="header-anchor" href="#\u5B9E\u65BD\u654F\u6377-\u521B\u5EFA\u654F\u6377\u73AF\u5883" aria-hidden="true">#</a> \u5B9E\u65BD\u654F\u6377\uFF1A\u521B\u5EFA\u654F\u6377\u73AF\u5883</h1><h2 id="\u4ECE\u654F\u6377\u601D\u7EF4\u5F00\u59CB" tabindex="-1"><a class="header-anchor" href="#\u4ECE\u654F\u6377\u601D\u7EF4\u5F00\u59CB" aria-hidden="true">#</a> \u4ECE\u654F\u6377\u601D\u7EF4\u5F00\u59CB</h2><ul><li>\u9879\u76EE\u56E2\u961F\u5982\u4F55\u4EE5\u654F\u6377\u65B9\u5F0F\u884C\u52A8</li><li>\u4E3A\u4E86\u4F7F\u4E0B\u4E00\u4EA4\u4ED8\u5468\u671F\u53D7\u76CA\uFF0C\u56E2\u961F\u9700\u8981\u5FEB\u901F\u4EA4\u4ED8\u90A3\u4E9B\u6210\u679C\u5E76\u83B7\u5F97\u65E9\u671F\u53CD\u9988</li><li>\u56E2\u961F\u5982\u4F55\u4EE5\u4E00\u79CD\u900F\u660E\u7684\u65B9\u5F0F\u884C\u52A8</li><li>\u4E3A\u4E86\u4E13\u6CE8\u4E8E\u9AD8\u4F18\u5148\u7EA7\u7684\u9879\u76EE\uFF0C\u53EF\u4EE5\u907F\u514D\u54EA\u4E9B\u5DE5\u4F5C\uFF1F</li><li>\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u5BF9\u56E2\u961F\u8FBE\u6210\u76EE\u6807\u6709\u4F55\u76CA\u5904\uFF1F</li></ul><h2 id="\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u4E3A\u56E2\u961F\u8D4B\u6743" tabindex="-1"><a class="header-anchor" href="#\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u4E3A\u56E2\u961F\u8D4B\u6743" aria-hidden="true">#</a> \u4EC6\u4EBA\u5F0F\u9886\u5BFC\u4E3A\u56E2\u961F\u8D4B\u6743</h2><p>\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u662F\u901A\u8FC7\u5BF9\u56E2\u961F\u670D\u52A1\u6765\u9886\u5BFC\u56E2\u961F\u7684\u5B9E\u8DF5\uFF0C\u6CE8\u91CD\u7406\u89E3\u548C\u5173\u6CE8\u56E2\u961F\u6210\u5458\u7684\u9700\u8981\u548C\u53D1\u5C55\uFF0C\u65E8\u5728\u4F7F\u56E2\u961F\u5C3D\u53EF\u80FD\u8FBE\u5230\u6700\u9AD8\u7EE9\u6548\u3002\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u7684\u4F5C\u7528\u4F7F\u4FC3\u8FDB\u56E2\u961F\u53D1\u73B0\u548C\u5B9A\u4E49\u654F\u6377\u3002\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u5B9E\u8DF5\u5E76\u4F20\u64AD\u654F\u6377\u3002\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u6309\u7167\u4E00\u4E0B\u987A\u5E8F\u4ECE\u4E8B\u9879\u76EE\u5DE5\u4F5C\uFF1A</p><ul><li>\u76EE\u7684 <ul><li>\u4E0E\u56E2\u961F\u4E00\u8D77\u5B9A\u4E49\u201D\u4E3A\u4EC0\u4E48\u201C\u6216\u76EE\u7684\uFF0C\u4EE5\u4FBF\u56F4\u7ED5\u9879\u76EE\u76EE\u6807\u8FDB\u884C\u5408\u4F5C\u4E92\u52A8</li></ul></li><li>\u4EBA\u5458 <ul><li>\u9F13\u52B1\u56E2\u961F\u521B\u9020\u4E00\u4E2A\u4EBA\u4EBA\u90FD\u80FD\u6210\u529F\u7684\u73AF\u5883</li><li>\u8981\u6C42\u6BCF\u4E2A\u56E2\u961F\u6210\u5458\u5728\u9879\u76EE\u5DE5\u4F5C\u4E2D\u505A\u51FA\u8D21\u732E</li></ul></li><li>\u8FC7\u7A0B <ul><li>\u4E0D\u8981\u8BA1\u5212\u9075\u5FAA\u201D\u5B8C\u7F8E\u201C\u7684\u654F\u6377\u8FC7\u7A0B\uFF0C\u800C\u662F\u8981\u6CE8\u91CD\u7ED3\u679C</li><li>\u4EA4\u4ED8\u4EF7\u503C\u5E76\u53CD\u601D\u4EA7\u54C1\u548C\u8FC7\u7A0B</li></ul></li></ul><p>\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u7684\u7279\u5F81\u8BA9\u9879\u76EE\u9886\u5BFC\u53D8\u5F97\u66F4\u52A0\u654F\u6377\uFF0C\u4FC3\u8FDB\u56E2\u961F\u7684\u6210\u529F\uFF1A</p><ul><li>\u63D0\u5347\u81EA\u6211\u610F\u8BC6</li><li>\u503E\u542C</li><li>\u4E3A\u56E2\u961F\u670D\u52A1</li><li>\u5E2E\u52A9\u4ED6\u4EBA\u6210\u957F</li><li>\u5F15\u5BFC\u4E0E\u63A7\u5236</li><li>\u4FC3\u8FDB\u5B89\u5168\u3001\u5C0A\u91CD\u4E0E\u4FE1\u4EFB</li><li>\u4FC3\u8FDB\u4ED6\u4EBA\u7ECF\u5386\u548C\u624D\u667A\u63D0\u5347</li></ul><p>\u6210\u529F\u7684\u654F\u6377\u56E2\u961F\u4FE1\u5949\u6210\u957F\u601D\u7EF4\u6A21\u5F0F\uFF0C\u56E2\u961F\u6210\u5458\u81EA\u5DF1\u80FD\u591F\u5B66\u5230\u65B0\u6280\u80FD\u3002</p><h3 id="\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u7684\u804C\u8D23" tabindex="-1"><a class="header-anchor" href="#\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u7684\u804C\u8D23" aria-hidden="true">#</a> \u4EC6\u4EBA\u5F0F\u9886\u5BFC\u7684\u804C\u8D23</h3><p>\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u901A\u8FC7\u7BA1\u7406\u5173\u7CFB\uFF0C\u5728\u56E2\u961F\u5185\u548C\u7EC4\u7EC7\u4E2D\u5EFA\u7ACB\u6C9F\u901A\u4E0E\u534F\u4F5C\u3002</p><ul><li><p>\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u7684\u4FC3\u8FDB\u4F5C\u7528</p><ul><li>\u5DE5\u4F5C\u91CD\u70B9\u4ECE\u201D\u7BA1\u7406\u534F\u8C03\u201C\u8F6C\u5411\u201D\u4FC3\u8FDB\u5408\u4F5C\u201C\u3002\u5E2E\u52A9\u6BCF\u4E2A\u4EBA\u5404\u5C3D\u6240\u80FD\u5730\u601D\u8003\u548C\u5DE5\u4F5C\u3002\u9F13\u52B1\u56E2\u961F\u53C2\u4E0E\u3001\u7406\u89E3\uFF0C\u5E76\u5BF9\u56E2\u961F\u8F93\u51FA\u5171\u540C\u627F\u62C5\u8D23\u4EFB\u3002\u5E2E\u52A9\u56E2\u961F\u521B\u5EFA\u53EF\u63A5\u53D7\u7684\u89E3\u51B3\u65B9\u6848\u3002</li><li>\u4FC3\u8FDB\u56E2\u961F\u5185\u90E8\u548C\u56E2\u961F\u4E4B\u95F4\u7684\u5408\u4F5C\u548C\u5BF9\u8BDD\uFF0C\u53D1\u73B0\u74F6\u9888\u5E76\u89E3\u51B3\u3002</li><li>\u9F13\u52B1\u5927\u5BB6\u901A\u8FC7\u4EA4\u4E92\u5F0F\u4F1A\u8BAE\u3001\u975E\u6B63\u5F0F\u5BF9\u8BDD\u548C\u77E5\u8BC6\u5171\u4EAB\u5C55\u5F00\u534F\u4F5C\u3002</li></ul></li><li><p>\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u6D88\u9664\u7EC4\u7EC7\u969C\u788D</p><ul><li>\u5BA1\u89C6\u963B\u788D\u56E2\u961F\u654F\u6377\u6216\u7EC4\u7EC7\u654F\u6377\u7684\u8FC7\u7A0B\uFF0C\u5E76\u52AA\u529B\u4F7F\u5176\u5408\u7406\u5316\u3002</li><li>\u6D88\u9664\u7EC4\u7EC7\u969C\u788D</li></ul></li><li><p>\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u4E3A\u4ED6\u4EBA\u8D21\u732E\u94FA\u8DEF</p><ul><li>\u4E3A\u56E2\u961F\u94FA\u8DEF\uFF0C\u8BA9\u56E2\u961F\u5C3D\u5176\u6240\u80FD</li><li>\u56E2\u961F\u6210\u5458\u8FD8\u8981\u91CD\u89C6\u81EA\u8EAB\u7684\u4EBA\u9645\u5173\u7CFB\u6280\u80FD\u548C\u60C5\u5546\u6280\u80FD</li><li>\u56E2\u961F\u6210\u5458\u8981\u52AA\u529B\u5C55\u793A\u66F4\u591A\u7684\u4E3B\u52A8\u6027\u3001\u6B63\u76F4\u3001\u60C5\u5546\u3001\u8BDA\u5B9E\u3001\u5408\u4F5C\u6001\u5EA6\u3001\u8C26\u900A\u548C\u4EE5\u4E0D\u540C\u65B9\u5F0F\u6C9F\u901A\u7684\u610F\u613F</li></ul></li><li><p>\u8003\u8651\u8FD9\u4E9B\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u7684\u804C\u8D23</p><ul><li>\u6559\u80B2\u76F8\u5173\u65B9\uFF0C\u4F7F\u5176\u4E86\u89E3\u4E3A\u4EC0\u4E48\u8981\u654F\u6377\u4EE5\u53CA\u5982\u4F55\u654F\u6377\u3002\u6839\u636E\u4F18\u5148\u7EA7\u8BF4\u660E\u5546\u4E1A\u4EF7\u503C\u7684\u597D\u5904\uFF0C\u5BF9\u88AB\u8D4B\u6743\u56E2\u961F\u52A0\u5F3A\u95EE\u8D23\uFF0C\u63D0\u9AD8\u5DE5\u4F5C\u6548\u7387\uFF0C\u5E76\u901A\u8FC7\u66F4\u9891\u7E41\u7684\u8BC4\u5BA1\u6539\u8FDB\u8D28\u91CF</li><li>\u901A\u8FC7\u6307\u5BFC\u3001\u9F13\u52B1\u548C\u5E2E\u52A9\u4E3A\u56E2\u961F\u63D0\u4F9B\u652F\u6301\u3002\u5021\u5BFC\u56E2\u961F\u6210\u5458\u7684\u57F9\u8BAD\u548C\u804C\u4E1A\u53D1\u5C55\u3002</li><li>\u901A\u8FC7\u6280\u672F\u9879\u76EE\u7BA1\u7406\u6D3B\u52A8\uFF0C\u5982\u91CF\u5316\u98CE\u9669\u5206\u6790\u6765\u5E2E\u52A9\u56E2\u961F\u3002</li><li>\u5E86\u795D\u56E2\u961F\u7684\u6210\u529F\uFF0C\u4E3A\u56E2\u961F\u4E0E\u5916\u90E8\u56E2\u961F\u5408\u4F5C\u63D0\u4F9B\u652F\u6301\uFF0C\u5E76\u8D77\u5230\u6865\u6881\u4F5C\u7528\u3002</li></ul></li><li><p>\u9879\u76EE\u7ECF\u7406\u5728\u654F\u6377\u73AF\u5883\u4E2D\u7684\u89D2\u8272</p><p>\u9879\u76EE\u7ECF\u7406\u7684\u4EF7\u503C\u4E0D\u5728\u4E8E\u4ED6\u4EEC\u7684\u5C97\u4F4D\uFF0C\u800C\u5728\u4E8E\u4ED6\u4EEC\u80FD\u591F\u8BA9\u6BCF\u4E2A\u4EBA\u90FD\u53D8\u5F97\u66F4\u597D\u3002</p><p>\u9879\u76EE\u7ECF\u7406\uFF1A\u7531\u6267\u884C\u7EC4\u7EC7\u59D4\u6D3E \uFF0C\u9886\u5BFC\u56E2\u961F\u5B9E\u73B0\u9879\u76EE\u76EE\u6807\u7684\u4E2A\u4EBA</p></li></ul><h2 id="\u56E2\u961F\u6784\u6210" tabindex="-1"><a class="header-anchor" href="#\u56E2\u961F\u6784\u6210" aria-hidden="true">#</a> \u56E2\u961F\u6784\u6210</h2><p>\u8981\u5584\u4E8E\u6FC0\u52B1\u9879\u76EE\u4EBA\u5458\uFF0C\u4E3A\u4ED6\u4EEC\u63D0\u4F9B\u6240\u9700\u7684\u73AF\u5883\u548C\u652F\u6301\uFF0C\u4FE1\u4EFB\u4ED6\u4EEC\u80FD\u591F\u5B8C\u6210\u5DE5\u4F5C\u3002</p><p>\u56E2\u961F\u5728\u8003\u8651\u5982\u4F55\u4F18\u5316\u4EF7\u503C\u6D41\u65F6\uFF0C\u4EE5\u4E0B\u597D\u5904\u662F\u663E\u800C\u6613\u89C1\u7684\uFF1A</p><ul><li>\u4EBA\u5458\u66F4\u6709\u53EF\u80FD\u5408\u4F5C</li><li>\u56E2\u961F\u66F4\u5FEB\u5730\u5B8C\u6210\u6709\u4EF7\u503C\u7684\u5DE5\u4F5C</li><li>\u7531\u4E8E\u4E0D\u4ECE\u4E8B\u591A\u4EFB\u52A1\uFF0C\u4E5F\u4E0D\u5FC5\u91CD\u65B0\u5EFA\u7ACB\u73AF\u5883\uFF0C\u56E2\u961F\u51CF\u5C11\u4E86\u65F6\u95F4\u6D6A\u8D39</li></ul><h3 id="\u654F\u6377\u56E2\u961F" tabindex="-1"><a class="header-anchor" href="#\u654F\u6377\u56E2\u961F" aria-hidden="true">#</a> \u654F\u6377\u56E2\u961F</h3><ul><li>\u56E2\u961F\u8D8A\u662F\u9650\u5236\u5176\u5728\u5236\u54C1\uFF0C\u56E2\u961F\u6210\u5458\u5C31\u8D8A\u6709\u53EF\u80FD\u901A\u8FC7\u5408\u4F5C\u6765\u52A0\u5FEB\u6574\u4E2A\u56E2\u961F\u7684\u5DE5\u4F5C\u3002</li><li>\u56E2\u961F\u5728\u7ED9\u5B9A\u65F6\u95F4\u89E3\u51B3\u6240\u6709\u7684\u9700\u6C42\uFF0C\u7136\u540E\u8BD5\u56FE\u5B8C\u6210\u6240\u6709\u7684\u8BBE\u8BA1\uFF0C\u7EE7\u800C\u53C8\u53BB\u5B8C\u6210\u6240\u6709\u7684\u6784\u5EFA\uFF0C\u5C31\u4F1A\u53D1\u751F\u8FF7\u4F60\u7011\u5E03\u7684\u60C5\u51B5\u3002\u5728\u6784\u5EFA\u4E2D\u6216\u6784\u5EFA\u540E\u6D4B\u8BD5\u4E2D\u7684\u67D0\u4E00\u65F6\u523B\uFF0C\u56E2\u961F\u4F1A\u610F\u8BC6\u5230\u5458\u7EBF\u7684\u5047\u8BBE\u5DF2\u7ECF\u4E0D\u518D\u6709\u6548\uFF0C\u56E2\u961F\u89E3\u51B3\u6240\u6709\u7684\u9700\u6C42\u6839\u672C\u662F\u5728\u6D6A\u8D39\u65F6\u95F4\u3002\u76F8\u53CD\uFF0C\u5F53\u56E2\u961F\u5408\u4F5C\u6253\u9020\u5168\u90E8\u529F\u80FD\u4E2D\u7684\u5C11\u91CF\u529F\u80FD\u65F6\uFF0C\u968F\u7740\u5DE5\u4F5C\u7684\u63A8\u8FDB\u548C\u4EA4\u4ED8\u5C11\u91CF\u5DF2\u5B8C\u6210\u7684\u529F\u80FD\uFF0C\u4ED6\u4EEC\u4E5F\u5728\u4E0D\u65AD\u5B66\u4E60\u3002</li><li>\u6210\u529F\u654F\u6377\u56E2\u961F\u7684\u5C5E\u6027\uFF1A</li></ul><table><thead><tr><th>\u5C5E\u6027</th><th>\u76EE\u6807</th></tr></thead><tbody><tr><td>\u4E13\u95E8\u4EBA\u5458</td><td>\u4E13\u5FC3\u81F4\u5FD7\uFF0C\u63D0\u9AD8\u5DE5\u4F5C\u6548\u7387\uFF1B\u5C11\u4E8E\u5341\u4EBA\u7684\u6548\u6027\u56E2\u961F</td></tr><tr><td>\u8DE8\u804C\u80FD\u56E2\u961F\u6210\u5458</td><td>\u9891\u7E41\u5F00\u53D1\u4E0E\u4EA4\u4ED8\uFF1B\u4F5C\u4E3A\u4E00\u4E2A\u72EC\u7ACB\u56E2\u961F\u4EA4\u4ED8\u5B8C\u6210\u7684\u4EF7\u503C\uFF1B\u4E3A\u5B8C\u6210\u4EFB\u52A1\uFF0C\u6574\u5408\u6240\u6709\u5DE5\u4F5C\u6D3B\u52A8\uFF1B\u4ECE\u56E2\u961F\u5185\u90E8\u548C\u5916\u90E8\uFF08\u5982\u4EA7\u54C1\u8D1F\u8D23\u4EBA\uFF09\u63D0\u4F9B\u53CD\u9988</td></tr><tr><td>\u96C6\u4E2D\u529E\u516C\u6216\u6709\u80FD\u529B\u5E94\u5BF9\u529E\u516C\u5730\u70B9\u4E0D\u540C\u5E26\u6765\u7684\u4EFB\u4F55\u6311\u6218</td><td>\u6539\u5584\u6C9F\u901A\uFF1B\u63D0\u9AD8\u56E2\u961F\u52A8\u529B\uFF1B\u77E5\u8BC6\u5171\u4EAB\uFF1B\u964D\u4F4E\u5B66\u4E60\u6210\u672C\uFF1B\u80FD\u591F\u81F4\u529B\u4E8E\u76F8\u4E92\u5408\u4F5C</td></tr><tr><td>\u7531\u901A\u624D\u548C\u4E13\u5BB6\u7EC4\u6210\u7684\u6DF7\u5408\u56E2\u961F</td><td>\u4E13\u5BB6\u63D0\u4F9B\u4E13\u95E8\u6280\u80FD\uFF0C\u901A\u624D\u63D0\u4F9B\u4ECE\u4E8B\u4E0D\u540C\u5DE5\u4F5C\u7684\u7075\u6D3B\u6027\uFF1B\u56E2\u961F\u5177\u6709\u4E13\u4E1A\u80FD\u529B\uFF0C\u5F80\u5F80\u6210\u4E3A\u901A\u624D\u578B\u4E13\u5BB6\uFF0C\u4ED6\u4EEC\u65E2\u6709\u4E13\u573A\u53C8\u6709\u591A\u79CD\u6280\u80FD\u7ECF\u9A8C</td></tr><tr><td>\u7A33\u5B9A\u7684\u5DE5\u4F5C\u73AF\u5883</td><td>\u5F7C\u6B64\u4F9D\u8D56\u5B9E\u73B0\u4EA4\u4ED8\uFF1B\u5BF9\u5DE5\u4F5C\u65B9\u6CD5\u4E92\u76F8\u8BA4\u540C\uFF1B\u7B80\u5316\u56E2\u961F\u6210\u672C\u6838\u7B97\uFF08\u8FD0\u8F6C\u7387\uFF09\uFF1B\u77E5\u8BC6\u8D44\u672C\u7684\u4FDD\u6709\u548C\u53D1\u5C55</td></tr></tbody></table><h4 id="\u654F\u6377\u7684\u89D2\u8272" tabindex="-1"><a class="header-anchor" href="#\u654F\u6377\u7684\u89D2\u8272" aria-hidden="true">#</a> \u654F\u6377\u7684\u89D2\u8272</h4><ul><li>\u8DE8\u804C\u80FD\u56E2\u961F\u6210\u5458</li><li>\u4EA7\u54C1\u8D1F\u8D23\u4EBA</li><li>\u56E2\u961F\u4FC3\u8FDB\u8005</li></ul><h3 id="\u4E13\u804C\u5C0F\u7EC4\u6210\u5458" tabindex="-1"><a class="header-anchor" href="#\u4E13\u804C\u5C0F\u7EC4\u6210\u5458" aria-hidden="true">#</a> \u4E13\u804C\u5C0F\u7EC4\u6210\u5458</h3><ul><li>\u591A\u4EFB\u52A1\u5904\u7406\u51CF\u7F13\u4E86\u6574\u4E2A\u56E2\u961F\u7684\u8FDB\u5C55\uFF0C\u56E0\u4E3A\u56E2\u961F\u6210\u5458\u8981\u6D6A\u8D39\u65F6\u95F4\u5207\u6362\u73AF\u5883\u548C/\u6216\u4E92\u76F8\u7B49\u5F85\u5B8C\u6210\u5176\u4ED6\u5DE5\u4F5C</li><li>\u4EFB\u52A1\u5207\u6362\u65F6\uFF0C\u4EBA\u5458\u5DE5\u4F5C\u6548\u7387\u7684\u635F\u5931\u5728 20% \u5230 40% \u4E4B\u95F4</li><li>\u4EBA\u4EEC\u5728\u4E00\u5FC3\u591A\u7528\u7684\u65F6\u5019\u66F4\u5BB9\u6613\u72AF\u9519\uFF0C\u4EFB\u52A1\u5207\u6362\u6D88\u8017\u5DE5\u4F5C\u8BB0\u5FC6\uFF0C\u4EBA\u4EEC\u5728\u591A\u4EFB\u52A1\u5904\u7406\u65F6\u4E0D\u592A\u53EF\u80FD\u8BB0\u4F4F\u76F8\u5E94\u5DE5\u4F5C\u7684\u80CC\u666F</li><li>\u5BF9\u6BCF\u4E2A\u4EBA\uFF08\u4E13\u5BB6\u548C\u56E2\u961F\uFF09\u8BBE\u5B9A\u671F\u671B\uFF0C\u9610\u660E\u56E2\u961F\u627F\u8BFA\u4EA4\u4ED8\u7684\u6C34\u5E73\u3002\u5206\u914D\u517C\u804C\u4EBA\u5458\u4F1A\u7ED9\u9879\u76EE\u5E26\u6765\u98CE\u9669\u3002</li></ul><h3 id="\u56E2\u961F\u5DE5\u4F5C\u573A\u6240" tabindex="-1"><a class="header-anchor" href="#\u56E2\u961F\u5DE5\u4F5C\u573A\u6240" aria-hidden="true">#</a> \u56E2\u961F\u5DE5\u4F5C\u573A\u6240</h3><p>\u5206\u6563\u5F0F\u56E2\u961F\u7BA1\u7406\u5171\u540C\u7684\u4E00\u4E9B\u6280\u672F\u5305\u62EC\u9C7C\u7F38\u7A97\u53E3\u548C\u8FDC\u7A0B\u7ED3\u5BF9</p><ul><li>\u901A\u8FC7\u5728\u56E2\u961F\u5206\u5E03\u7684\u5404\u4E2A\u5730\u70B9\u4E4B\u95F4\u5EFA\u7ACB\u957F\u671F\u89C6\u9891\u4F1A\u8BAE\u94FE\u63A5\uFF0C\u521B\u5EFA\u4E00\u4E2A\u9C7C\u7F38\u7A97\u53E3</li><li>\u901A\u8FC7\u4F7F\u7528\u865A\u62DF\u4F1A\u8BAE\u5DE5\u5177\u6765\u5171\u4EAB\u5C4F\u5E55\uFF0C\u5305\u62EC\u8BED\u97F3\u548C\u89C6\u9891\u94FE\u63A5\uFF0C\u5EFA\u7ACB\u8FDC\u7A0B\u7ED3\u5BF9</li></ul><h3 id="\u514B\u670D\u7EC4\u7EC7\u5B64\u5C9B" tabindex="-1"><a class="header-anchor" href="#\u514B\u670D\u7EC4\u7EC7\u5B64\u5C9B" aria-hidden="true">#</a> \u514B\u670D\u7EC4\u7EC7\u5B64\u5C9B</h3><ul><li>\u6784\u5EFA\u62E5\u6709\u57FA\u672C\u4FE1\u4EFB\u548C\u5B89\u5168\u7684\u5DE5\u4F5C\u73AF\u5883\uFF0C\u786E\u4FDD\u6240\u6709\u56E2\u961F\u6210\u5458\u90FD\u6709\u5E73\u7B49\u7684\u8BDD\u8BED\u6743\uFF0C\u4ED6\u4EEC\u7684\u610F\u89C1\u90FD\u80FD\u88AB\u542C\u5230\u5E76\u5F97\u5230\u8003\u8651</li><li>\u7BA1\u7406\u4EBA\u5458\u9700\u8981\u5173\u6CE8\u70B9\u4E0D\u662F\u8D44\u6E90\u5229\u7528\u6548\u7387\uFF0C\u800C\u662F\u8FC7\u7A0B\u6548\u7387\uFF08\u548C\u57FA\u4E8E\u56E2\u961F\u7684\u6307\u6807\uFF09</li></ul>',28);function d(t,r){return e}var u=l(a,[["render",d],["__file","chapter4.html.vue"]]);export{u as default};
